#!/usr/bin/env node
/**
 * Tour Builder Topology Analyzer
 * Analyzes graph topology to surface structural signals for tour design.
 */

const fs = require('fs');
const path = require('path');

const inputPath = process.argv[2];
const outputPath = process.argv[3];

if (!inputPath || !outputPath) {
  console.error('Usage: node ua-tour-analyze.js <input.json> <output.json>');
  process.exit(1);
}

let data;
try {
  data = JSON.parse(fs.readFileSync(inputPath, 'utf8'));
} catch (err) {
  console.error('Failed to read input file:', err.message);
  process.exit(1);
}

const { nodes, edges, layers } = data;

// Build lookup maps
const nodeMap = new Map();
const fanIn = new Map();
const fanOut = new Map();

nodes.forEach(n => {
  nodeMap.set(n.id, n);
  fanIn.set(n.id, 0);
  fanOut.set(n.id, 0);
});

// Compute fan-in and fan-out
edges.forEach(e => {
  fanIn.set(e.target, (fanIn.get(e.target) || 0) + 1);
  fanOut.set(e.source, (fanOut.get(e.source) || 0) + 1);
});

// Entry point candidates scoring
const ENTRY_PATTERNS = [
  'index.', 'main.', 'app.', 'server.', 'Application.', 'Main.', 'Program.', 'config.ru'
];

function scoreEntryPoint(node) {
  let score = 0;
  const name = node.name || '';
  const filePath = node.filePath || '';

  // Filename matches entry patterns
  if (ENTRY_PATTERNS.some(p => name.startsWith(p.replace('.', '')))) {
    score += 3;
  }

  // Root level or one level deep
  const depth = filePath.split('/').filter(Boolean).length;
  if (depth <= 2) score += 1;

  // High fan-out (top 10%)
  const fanOutVals = [...fanOut.values()].sort((a, b) => b - a);
  const top10Threshold = fanOutVals[Math.floor(fanOutVals.length * 0.1)] || 0;
  if ((fanOut.get(node.id) || 0) >= top10Threshold) score += 1;

  // Low fan-in (bottom 25%)
  const fanInVals = [...fanIn.values()].sort((a, b) => a - b);
  const bottom25Threshold = fanInVals[Math.floor(fanInVals.length * 0.25)] || 0;
  if ((fanIn.get(node.id) || 0) <= bottom25Threshold) score += 1;

  return score;
}

// Compute entry point candidates
const entryCandidates = nodes
  .filter(n => n.type === 'file')
  .map(n => ({ ...n, entryScore: scoreEntryPoint(n) }))
  .sort((a, b) => b.entryScore - a.entryScore)
  .slice(0, 5)
  .map(n => ({ id: n.id, score: n.entryScore, name: n.name, summary: n.summary }));

// Top fan-in (importance)
const fanInRanking = [...fanIn.entries()]
  .sort((a, b) => b[1] - a[1])
  .slice(0, 20)
  .map(([id, count]) => ({ id, fanIn: count, name: nodeMap.get(id)?.name || id }))
  .filter(r => nodeMap.has(r.id));

// Top fan-out (scope)
const fanOutRanking = [...fanOut.entries()]
  .sort((a, b) => b[1] - a[1])
  .slice(0, 20)
  .map(([id, count]) => ({ id, fanOut: count, name: nodeMap.get(id)?.name || id }))
  .filter(r => nodeMap.has(r.id));

// BFS from top code entry point
const topCodeEntry = entryCandidates.find(c => !c.id.startsWith('document:'));
const startNodeId = topCodeEntry?.id || nodes.find(n => n.type === 'file')?.id;

const bfsTraversal = { startNode: startNodeId, order: [], depthMap: {}, byDepth: {} };
if (startNodeId) {
  const visited = new Set();
  const queue = [{ id: startNodeId, depth: 0 }];
  const edgeMap = new Map();

  edges.forEach(e => {
    if (!edgeMap.has(e.source)) edgeMap.set(e.source, []);
    edgeMap.get(e.source).push(e.target);
  });

  while (queue.length > 0) {
    const { id, depth } = queue.shift();
    if (visited.has(id)) continue;
    visited.add(id);
    bfsTraversal.order.push(id);
    bfsTraversal.depthMap[id] = depth;
    if (!bfsTraversal.byDepth[depth]) bfsTraversal.byDepth[depth] = [];
    bfsTraversal.byDepth[depth].push(id);

    const neighbors = edgeMap.get(id) || [];
    neighbors.forEach(neighbor => {
      if (!visited.has(neighbor)) {
        queue.push({ id: neighbor, depth: depth + 1 });
      }
    });
  }
}

// Non-code files inventory
const nonCodeFiles = {
  documentation: [],
  infrastructure: [],
  data: [],
  config: []
};

nodes.forEach(n => {
  if (n.type === 'document') {
    nonCodeFiles.documentation.push({ id: n.id, name: n.name, summary: n.summary });
  } else if (['service', 'pipeline', 'resource'].includes(n.type)) {
    nonCodeFiles.infrastructure.push({ id: n.id, name: n.name, summary: n.summary });
  } else if (['table', 'schema', 'endpoint'].includes(n.type)) {
    nonCodeFiles.data.push({ id: n.id, name: n.name, summary: n.summary });
  } else if (n.type === 'config') {
    nonCodeFiles.config.push({ id: n.id, name: n.name, summary: n.summary });
  }
});

// Clusters - bidirectional relationships
const bidirectional = new Map();
edges.forEach(e => {
  if (e.type === 'imports' || e.type === 'calls') {
    const revKey = `${e.target}|${e.source}`;
    if (bidirectional.has(revKey)) {
      if (!bidirectional.get(revKey).includes(e.source)) {
        bidirectional.get(revKey).push(e.source);
      }
    } else {
      bidirectional.set(e.source + '|' + e.target, [e.source, e.target]);
    }
  }
});

// Find clusters (nodes with 2+ edges between them)
const clusterMap = new Map();
bidirectional.forEach((pair, key) => {
  pair.forEach(nodeId => {
    if (!clusterMap.has(nodeId)) clusterMap.set(nodeId, new Set());
    pair.forEach(other => {
      if (other !== nodeId) clusterMap.get(nodeId).add(other);
    });
  });
});

const clusters = [];
const processed = new Set();
clusterMap.forEach((members, nodeId) => {
  if (members.size >= 1 && members.size <= 4) {
    const clusterKey = [nodeId, ...members].sort().join('|');
    if (!processed.has(clusterKey)) {
      processed.add(clusterKey);
      clusters.push({
        nodes: [nodeId, ...members],
        edgeCount: members.size + 1
      });
    }
  }
});

// Node summary index
const nodeSummaryIndex = {};
nodes.forEach(n => {
  nodeSummaryIndex[n.id] = { name: n.name, type: n.type, summary: n.summary };
});

// Layers
const layerList = (layers || []).map(l => ({
  id: l.id,
  name: l.name,
  description: l.description
}));

const result = {
  scriptCompleted: true,
  entryPointCandidates: entryCandidates,
  fanInRanking,
  fanOutRanking,
  bfsTraversal,
  nonCodeFiles,
  clusters: clusters.slice(0, 10),
  layers: {
    count: layerList.length,
    list: layerList
  },
  nodeSummaryIndex,
  totalNodes: nodes.length,
  totalEdges: edges.length
};

fs.writeFileSync(outputPath, JSON.stringify(result, null, 2));
console.log('Analysis complete. Nodes:', result.totalNodes, 'Edges:', result.totalEdges);
process.exit(0);

